@app.route('/waitlist', methods=['POST'])
def join_waitlist():
    party_size_str = request.form.get('party_size', '').strip()
    try:
        party_size = int(party_size_str)
        if party_size < 1:
            return redirect(url_for('waitlist'))
    except ValueError:
        return redirect(url_for('waitlist'))

    waitlist_data = load_waitlist()
    # Check if user already in active waitlist
    for w in waitlist_data:
        if w['username'] == CURRENT_USERNAME and w['status'] == 'Active':
            # Already on waitlist, no add
            return redirect(url_for('waitlist'))

    max_id = max([w['waitlist_id'] for w in waitlist_data], default=0)
    new_id = max_id + 1
    now_str = datetime.now().strftime('%Y-%m-%d %H:%M:%S')

    new_waitlist_entry = {
        'waitlist_id': new_id,
        'username': CURRENT_USERNAME,
        'party_size': party_size,
        'join_time': now_str,
        'status': 'Active'
    }
    waitlist_data.append(new_waitlist_entry)
    save_waitlist(waitlist_data)

    return redirect(url_for('waitlist'))

