@app.route('/write-review', methods=['POST'])
def submit_review():
    dish_id_str = request.form.get('dish_id', '').strip()
    rating_str = request.form.get('rating', '').strip()
    review_text = request.form.get('review_text', '').strip()

    try:
        dish_id = int(dish_id_str)
        rating = int(rating_str)
        if rating < 1 or rating > 5:
            return redirect(url_for('write_review'))
    except ValueError:
        return redirect(url_for('write_review'))

    # Validate dish exists
    menu_data = load_menu()
    dish_exists = any(d['dish_id'] == dish_id for d in menu_data)
    if not dish_exists:
        return redirect(url_for('write_review'))

    reviews_data = load_reviews()
    max_id = max([r['review_id'] for r in reviews_data], default=0)
    new_id = max_id + 1
    now_str = datetime.now().strftime('%Y-%m-%d')

    new_review = {
        'review_id': new_id,
        'username': CURRENT_USERNAME,
        'dish_id': dish_id,
        'rating': rating,
        'review_text': review_text,
